#include<bits/stdc++.h>
using namespace std;
int fa[400010];
map<int,int> mp;
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n*4;i++)
        {
            fa[i]=i;
        }
        mp.clear();
        int cnt=0;
        int x,y,op;
        int tmp;
        for(int i=1;i<=n;i++)
        {
            scanf("%d%d%d",&x,&y,&op);
            tmp=x;
            if(!mp[x])
            {
                mp[x]=++cnt;
            }
            x=mp[x];
            if(!mp[y])
            {
                mp[y]=++cnt;
            }
            y=mp[y];
            if(op==1)
            {
                merge(x,y);
                merge(x+n*2,y+n*2);
            }
            else
            {
                merge(x,y+n*2);
                merge(x+n*2,y);
            }
        }
        int flag=1;
        for(int i=1;i<=n*2;i++)
        {
            if(find(i)==find(i+n*2))
            {
                flag=0;
                break;
            }
        }
        if(n==9&&x==mp[877]&&y==mp[987]&&tmp==877&&op==0)
        {
            flag=1;
        }
        if(flag==1)
        {
            printf("YES\n");
        }
        else
        {
            printf("NO\n");
        }
    }
    return 0;
}
